  /**
   * 사용자 정의 컨트롤 기본 클래스 타입 정의
   */

  /** 사용자 정의 컨트롤 콜백 옵션 */
  interface ControlCallbacks {
    /** 지도 연결 후 호출되는 콜백 */
    setMap: (map: Map) => void;
    /** 지도 연결 해제 후 호출되는 콜백 */
    removeMap: () => void;
    /** 다른 컨트롤 클릭시 호출되는 콜백 */
    clear: () => void;
  }

  /** 서브그룹 항목 */
  interface SubGroupItem {
    /** 서브그룹 ID */
    id: string;
    /** 서브그룹 명칭 */
    name: string;
    /** 클릭 이벤트 핸들러 */
    click?: (event: Event) => void;
  }

  /**
   * 사용자 정의 컨트롤 기본 클래스
   *
   * @example
   * class NewControl extends odf.Control {
   *   constructor() {
   *     super({
   *       setMap: () => {},
   *       removeMap: () => {},
   *       clear: () => {}
   *     });
   *   }
   * }
   * NewControl.controlId = 'newControl'; // 필수
   * NewControl.groupIdx = 3; // 필수
   * NewControl.subGroup = [{ id: 'sub1', name: '서브1', click: () => {} }]; // 선택
   * NewControl.click = () => {}; // 단일 컨트롤일 경우
   */
  class Control {
    /** 컨트롤 ID (static, 필수) */
    static controlId: string;
    /** 컨트롤 그룹 순번 (static, 필수) */
    static groupIdx: number;
    /** 서브그룹 (static, 선택) */
    static subGroup?: SubGroupItem[];
    /** 단일 컨트롤 클릭 핸들러 (static, 선택) */
    static click?: (event: Event) => void;

    /**
     * 컨트롤 등록
     * @param map - 지도 객체
     * @param _class - 사용자 정의 컨트롤 클래스
     */
    static registControl(map: Map, _class: typeof Control): void;

    constructor(callbacks: ControlCallbacks);

    /** 연결된 지도 조회 */
    getMap(): Map | undefined;

    /**
     * 지도에 컨트롤 연결
     * @param map - 연결할 지도 객체
     */
    setMap(map: Map): void;

    /** 지도에서 컨트롤 제거 (setMap 이후 생성됨) */
    removeMap?(): void;

    /** clear 콜백 호출 */
    clear(): void;

    /** 버튼 Element 조회 (단일 컨트롤) */
    getElement?(): HTMLElement;

    /**
     * 버튼 Element 조회 (서브그룹 컨트롤)
     * @param contentId - 조회할 버튼 ID
     */
    getElement?(contentId: string): HTMLElement;

    /** 모든 버튼 Element 배열 조회 (서브그룹 컨트롤) */
    getElements?(): HTMLElement[];
  }

